mapper.insert:
INSERT  INTO TB_BBS_MASTER
      ( BBS_ID
      , BBS_TY_CODE
      , BBS_ATTRB_CODE
      , BBS_NM
      , BBS_INTRCN
      , REPLY_POSBL_AT
      , FILE_ATCH_POSBL_AT
      , ATCH_POSBL_FILE_NUMBER
      , ATCH_POSBL_FILE_SIZE
      , TMPLAT_ID
      , USE_AT
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{bbsId}
        , #{bbsTyCode}
        , #{bbsAttrbCode}
        , #{bbsNm}
        , #{bbsIntrcn}
        , #{replyPosblAt}
        , #{fileAtchPosblAt}
        , #{posblAtchFileNumber}
        , #{posblAtchFileSize}
        , #{tmplatId}
        , #{useAt}
        , #{frstRegisterId}
        , SYSDATE )

mapper.select:
SELECT /* TODO: 컬럼 명시 필요 */ * FROM ( SELECT ROWNUM RN , TB.* FROM ( SELECT A.BBS_ID , A.BBS_TY_CODE , B.CODE_NM AS BBS_TY_CODE_NM , A.BBS_ATTRB_CODE , C.CODE_NM AS BBS_ATTRB_CODE_NM , A.BBS_NM , A.TMPLAT_ID , A.USE_AT , TO_CHAR(A.FRST_REGIST_PNTTM, 'YYYY-MM-DD') AS FRST_REGIST_PNTTM FROM TB_BBS_MASTER A LEFT OUTER JOIN ( SELECT CODE_ID , CODE , CODE_NM FROM TB_CMMN_DETAIL_CODE WHERE CODE_ID = 'COM004' AND USE_AT = 'Y' ) B ON A.BBS_TY_CODE = B.CODE LEFT OUTER JOIN ( SELECT CODE_ID , CODE , CODE_NM FROM TB_CMMN_DETAIL_CODE WHERE CODE_ID = 'COM009' AND USE_AT = 'Y' ) C ON A.BBS_ATTRB_CODE = C.CODE WHERE 1=1
AND A.USE_AT = #{useAt}
AND A.BBS_NM LIKE '%' || #{searchWrd} || '%'
AND B.CODE_NM LIKE '%' || #{searchWrd} || '%'
ORDER BY A.FRST_REGIST_PNTTM DESC ) TB ) WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

mapper.update:
UPDATE  TB_BBS_MASTER
   SET  BBS_NM                 = #{bbsNm}
      , BBS_INTRCN             = #{bbsIntrcn}
      , FILE_ATCH_POSBL_AT     = #{fileAtchPosblAt}
      , ATCH_POSBL_FILE_NUMBER = #{posblAtchFileNumber}
      , ATCH_POSBL_FILE_SIZE   = #{posblAtchFileSize}
      , TMPLAT_ID              = #{tmplatId}
      , LAST_UPDUSR_ID         = #{lastUpdusrId}
      , LAST_UPDT_PNTTM        = SYSDATE
 WHERE  BBS_ID = #{bbsId}

UPDATE  TB_BBS_MASTER
   SET  USE_AT          = 'N'
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = SYSDATE
 WHERE  BBS_ID = #{bbsId}

