SELECT /* TODO: 컬럼 명시 필요 */ * FROM ( SELECT ROWNUM RN , TB.* FROM ( SELECT A.BBS_ID , A.BBS_TY_CODE , B.CODE_NM AS BBS_TY_CODE_NM , A.BBS_ATTRB_CODE , C.CODE_NM AS BBS_ATTRB_CODE_NM , A.BBS_NM , A.TMPLAT_ID , A.USE_AT , TO_CHAR(A.FRST_REGIST_PNTTM, 'YYYY-MM-DD') AS FRST_REGIST_PNTTM FROM TB_BBS_MASTER A LEFT OUTER JOIN ( SELECT CODE_ID , CODE , CODE_NM FROM TB_CMMN_DETAIL_CODE WHERE CODE_ID = 'COM004' AND USE_AT = 'Y' ) B ON A.BBS_TY_CODE = B.CODE LEFT OUTER JOIN ( SELECT CODE_ID , CODE , CODE_NM FROM TB_CMMN_DETAIL_CODE WHERE CODE_ID = 'COM009' AND USE_AT = 'Y' ) C ON A.BBS_ATTRB_CODE = C.CODE , TB_BBS_USE D WHERE A.BBS_ID = D.BBS_ID AND D.TRGET_ID = #{trgetId}
AND A.BBS_NM LIKE '%' || #{searchWrd} || '%'
AND B.CODE_NM LIKE '%' || #{searchWrd} || '%'
ORDER BY A.FRST_REGIST_PNTTM DESC ) TB ) WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT COUNT(A.BBS_ID) FROM TB_BBS_MASTER A LEFT OUTER JOIN ( SELECT CODE_ID , CODE , CODE_NM FROM TB_CMMN_DETAIL_CODE WHERE CODE_ID = 'COM004' AND USE_AT = 'Y' ) B ON A.BBS_TY_CODE = B.CODE LEFT OUTER JOIN ( SELECT CODE_ID , CODE , CODE_NM FROM TB_CMMN_DETAIL_CODE WHERE CODE_ID = 'COM009' AND USE_AT = 'Y' ) C ON A.BBS_ATTRB_CODE = C.CODE , TB_BBS_USE D WHERE A.BBS_ID = D.BBS_ID AND D.TRGET_ID = #{trgetId}
AND A.BBS_NM LIKE '%' || #{searchWrd} || '%'
AND B.CODE_NM LIKE '%' || #{searchWrd} || '%'
